function solve(n: number, edges: number[][], k: number): number {
    if (edges.length === 0) {
        return 0;
    }

    const sortedEdges = [...edges];
    sortedEdges.sort((a, b) => b[2] - a[2]);

    const maxEdgeTime = Math.max(...edges.map(e => e[2]));
    let low = 0;
    let high = maxEdgeTime + 1;

    const countComponents = (t: number): number => {
        const parent: number[] = new Array(n);
        const rank: number[] = new Array(n).fill(0);
        for (let i = 0; i < n; i++) {
            parent[i] = i;
        }

        const find = (x: number): number => {
            if (parent[x] !== x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        };

        const union = (x: number, y: number): void => {
            const rx = find(x);
            const ry = find(y);
            if (rx === ry) {
                return;
            }
            if (rank[rx] < rank[ry]) {
                parent[rx] = ry;
            } else if (rank[rx] > rank[ry]) {
                parent[ry] = rx;
            } else {
                parent[ry] = rx;
                rank[rx]++;
            }
        };

        let count = n;
        for (let i = 0; i < sortedEdges.length; i++) {
            const [u, v, timeVal] = sortedEdges[i];
            if (timeVal > t) {
                const ru = find(u);
                const rv = find(v);
                if (ru !== rv) {
                    union(u, v);
                    count--;
                }
            } else {
                break;
            }
        }
        return count;
    };

    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        const comps = countComponents(mid);
        if (comps >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;
}
```

